const p = msg.payload || {};
if (!p.trip_id) return null;
flow.set('lastTripId', p.trip_id);
msg.query = 'INSERT INTO telemetry (trip_id, ts, rpm, speed, coolant, intake, throttle, engine_load, voltage, fuel) VALUES ($1, to_timestamp($2/1000.0), $3,$4,$5,$6,$7,$8,$9,$10)';
msg.params = [p.trip_id, p.ts, p.rpm, p.speed, p.coolant, p.intake, p.throttle, p.load, p.voltage, p.fuel];
return msg;

const tripId = flow.get('lastTripId');
if (!tripId) return null;
msg.query = 'INSERT INTO trips (trip_id, started_at, ended_at, duration_s, distance_km, avg_speed, max_speed, avg_rpm, max_rpm, max_coolant, min_voltage, samples) SELECT trip_id, min(ts), max(ts), EXTRACT(EPOCH FROM (max(ts)-min(ts)))::int, COALESCE(SUM(speed * dt_h), 0), avg(speed), max(speed), avg(rpm), max(rpm), max(coolant), min(voltage), count(*) FROM (SELECT trip_id, ts, speed, rpm, coolant, voltage, EXTRACT(EPOCH FROM (ts - LAG(ts) OVER (PARTITION BY trip_id ORDER BY ts)))/3600.0 AS dt_h FROM telemetry WHERE trip_id = $1) q GROUP BY trip_id ON CONFLICT (trip_id) DO UPDATE SET ended_at=EXCLUDED.ended_at, duration_s=EXCLUDED.duration_s, distance_km=EXCLUDED.distance_km, avg_speed=EXCLUDED.avg_speed, max_speed=EXCLUDED.max_speed, avg_rpm=EXCLUDED.avg_rpm, max_rpm=EXCLUDED.max_rpm, max_coolant=EXCLUDED.max_coolant, min_voltage=EXCLUDED.min_voltage, samples=EXCLUDED.samples';
msg.params = [tripId];
return msg;
